
'use client';
import { useState, useEffect } from 'react';
import { Plant, PlantType } from '../type';
import { plants as initialPlants } from '../data';
import Link from 'next/link';
import axios from 'axios';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Select, SelectTrigger, SelectContent, SelectItem, SelectValue } from '@/components/ui/select';
import { PlusIcon } from 'lucide-react';
import {
  Pagination,
  PaginationContent,
  PaginationEllipsis,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from '@/components/ui/pagination';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from '@/components/ui/dialog';
export default function PlantsPage() {
  const [plants, setPlants] = useState<Plant[]>(initialPlants);
  const [newPlant, setNewPlant] = useState<Partial<Plant>>({});
  const [currentPage, setCurrentPage] = useState(1);
  const [showSuccessDialog, setShowSuccessDialog] = useState(false);
  const plantsPerPage = 12;

  // Pagination calculation
  const indexOfLastPlant = currentPage * plantsPerPage;
  const indexOfFirstPlant = indexOfLastPlant - plantsPerPage;
  const currentPlants = plants.slice(indexOfFirstPlant, indexOfLastPlant);
  const totalPages = Math.ceil(plants.length / plantsPerPage);

  const handleAdd = async () => {
    if (!newPlant.name || !newPlant.price || !newPlant.type) {
      // Instead of alert, you can show an error dialog if needed
      return;
    }

    const plant: Plant = {
      id: (plants.length + 1).toString(),
      name: newPlant.name,
      price: Number(newPlant.price),
      img: newPlant.img || 'https://placehold.co/800x600',
      description: newPlant.description || '',
      care: newPlant.care || '',
      type: newPlant.type as PlantType,
    };

    setPlants([...plants, plant]);
    setNewPlant({});
    setCurrentPage(1);
    setShowSuccessDialog(true); // Show success popup

    // Example: API call for adding plant
    /*
    try {
      const formData = new FormData();
      formData.append('name', newPlant.name);
      formData.append('price', String(newPlant.price));
      formData.append('type', newPlant.type);
      if (newPlant.file) formData.append('image', newPlant.file);

      await axios.post('/api/plants', formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
    } catch (error) {
      console.error('Failed to add plant', error);
    }
    */
  };

  return (
    <div className="p-4 md:p-6 max-w-7xl mx-auto">
      {/* Header with Add Plant Button */}
      <div className="flex flex-col sm:flex-row justify-between items-center mb-6 gap-3">
        <h1 className="text-2xl md:text-3xl font-bold">Plants</h1>
        <Dialog>
          <DialogTrigger asChild>
            <Button className="flex items-center gap-2">
              <PlusIcon size={16} /> Add New Plant
            </Button>
          </DialogTrigger>
          <DialogContent className="sm:max-w-lg">
            <DialogHeader>
              <DialogTitle>Add New Plant</DialogTitle>
            </DialogHeader>

            <div className="space-y-3 mt-2">
              <Input
                placeholder="Name"
                value={newPlant.name || ''}
                onChange={(e) => setNewPlant({ ...newPlant, name: e.target.value })}
              />
              <Input
                type="number"
                placeholder="Price"
                value={newPlant.price || ''}
                onChange={(e) => setNewPlant({ ...newPlant, price: Number(e.target.value) })}
              />
              <div>
                <label className="block text-sm font-medium mb-1">Upload Image</label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={(e) => {
                    if (e.target.files && e.target.files[0]) {
                      const file = e.target.files[0];
                      setNewPlant({
                        ...newPlant,
                        file,
                        img: URL.createObjectURL(file),
                      });
                    }
                  }}
                  className="block w-full text-sm text-gray-600"
                />
                {newPlant.img && (
                  <img
                    src={newPlant.img}
                    alt="Preview"
                    className="mt-2 w-full h-40 object-cover rounded"
                  />
                )}
              </div>
              <Input
                placeholder="Description"
                value={newPlant.description || ''}
                onChange={(e) => setNewPlant({ ...newPlant, description: e.target.value })}
              />
              <Input
                placeholder="Care"
                value={newPlant.care || ''}
                onChange={(e) => setNewPlant({ ...newPlant, care: e.target.value })}
              />
              <Select
                onValueChange={(value) => setNewPlant({ ...newPlant, type: value as PlantType })}
                value={newPlant.type || ''}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select Type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="regular tree">All Categories</SelectItem>
                  <SelectItem value="indoor">Indoor</SelectItem>
                  <SelectItem value="outdoor">Outdoor</SelectItem>
                  
                  <SelectItem value="fruit tree">Fruit Plants</SelectItem>
                   <SelectItem value="fruit tree">Water Plants</SelectItem>
                    <SelectItem value="fruit tree">Home Decoration</SelectItem>
                </SelectContent>
              </Select>

              <Button
                onClick={handleAdd}
                className="w-full flex justify-center items-center gap-2"
              >
                <PlusIcon size={16} /> Add Plant
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {/* Plants Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 mb-6">
        {currentPlants.map((plant) => (
          <Link key={plant.id} href={`/plants/${plant.id}`}>
            <Card className="cursor-pointer hover:shadow-lg transition-shadow duration-200">
              <CardHeader>
                <CardTitle className="truncate">{plant.name}</CardTitle>
              </CardHeader>
              <CardContent className="flex flex-col items-center">
                <img
                  src={plant.img}
                  alt={plant.name}
                  className="w-full h-40 sm:h-48 object-cover rounded mb-2"
                />
                <p className="font-semibold">${plant.price}</p>
                <p className="text-sm text-gray-500 capitalize">{plant.type}</p>
              </CardContent>
            </Card>
          </Link>
        ))}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <Pagination>
          <PaginationContent>
            <PaginationItem>
              <PaginationPrevious
                href="#"
                onClick={() => setCurrentPage((prev) => Math.max(prev - 1, 1))}
              />
            </PaginationItem>

            {[...Array(totalPages)].map((_, index) => (
              <PaginationItem key={index}>
                <PaginationLink
                  href="#"
                  isActive={currentPage === index + 1}
                  onClick={() => setCurrentPage(index + 1)}
                >
                  {index + 1}
                </PaginationLink>
              </PaginationItem>
            ))}

            {totalPages > 5 && <PaginationEllipsis />}

            <PaginationItem>
              <PaginationNext
                href="#"
                onClick={() => setCurrentPage((prev) => Math.min(prev + 1, totalPages))}
              />
            </PaginationItem>
          </PaginationContent>
        </Pagination>
      )}

      {/* ✅ Success Popup */}
      <Dialog open={showSuccessDialog} onOpenChange={setShowSuccessDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>✅ Plant Added!</DialogTitle>
          </DialogHeader>
          <p>Your new plant has been added successfully.</p>
          <DialogFooter>
            <Button onClick={() => setShowSuccessDialog(false)}>OK</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}


